import java.util.Scanner;
import java.util.ArrayList;
import java.util.List;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Use ArrayList for dynamic buffer handling
        List<Byte> buffer = new ArrayList<>();

        // Copy input bytes into the buffer
        for (byte b : input.getBytes()) {
            if (buffer.size() < 10) { // Limit buffer size to 10 bytes
                buffer.add(b);
            } else {
                break; // Prevent buffer overflow by breaking if size exceeds limit
            }
        }

        System.out.println("Input copied successfully!");
    }
}

